    SELECT MAX(SEQ_CURRVAL)+1
    FROM TBL_SEQUENCES
    WHERE SEQ_NAME = #{seqName}
    FOR UPDATE

UPDATE TBL_SEQUENCES
SET SEQ_CURRVAL = #{seqCurrval}
WHERE SEQ_NAME = #{seqName}

