SELECT COUNT(UML_CODE)
FROM TBL_MEMBER_LIBRARY
WHERE UML_UM_CODE = #{umCode}

mapper.update:
UPDATE TBL_CONTENTS_MASTER
SET UCM_READBOOK_COUNT = IFNULL(UCM_READBOOK_COUNT, 0) + 1
WHERE UCM_CODE = #{ucmCode}

mapper.select:
SELECT COUNT(UML_CODE)
FROM TBL_MEMBER_LIBRARY
