SELECT COUNT(UME_CODE)
FROM TBL_MEMBER_LIBRARY_BOOK
WHERE UME_UML_CODE = #{umlCode}
  AND UME_UCM_CODE = #{ucmCode}

SELECT UME_CODE, UME_STATUS
FROM TBL_MEMBER_LIBRARY_BOOK
WHERE UME_UM_CODE = #{umCode}
  AND UME_UCM_CODE = #{ucmCode}
LIMIT 1

SELECT COUNT(UME_CODE)
FROM TBL_MEMBER_LIBRARY_BOOK
WHERE UME_UM_CODE = #{umCode}
  AND UME_UCM_CODE = #{ucmCode}
  AND UME_STATUS = 'A'
  AND DATE(UME_INPUT_DATE) = DATE(NOW())

SELECT UIS_MAX_LIBRARY_IN_BOOK
FROM TBL_INSTITUTION_MASTER
WHERE UIS_CODE = #{uisCode}
